INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07090', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '呂蒙正相公不喜記人過。初參知政事，入朝堂，有朝士于簾內指之曰：「是小子亦參政耶？」蒙正佯為 不聞而過之。其同列怒，令詰其官位、姓名，蒙正遽止之。罷朝，同列猶不能平，悔不窮問。蒙正曰： 「一知其姓名，則終身不能復忘，固不如無知也。不問之，何損？」 根據上文，下列對呂蒙正的評論何者最適切？', '["以友輔仁", "寬宏大量", "舉直錯諸枉", "過則勿憚改"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07091', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「簡能而任之，擇善而從之，則智者盡其謀，勇者竭其力，仁者播其惠，信者效其忠。」（魏徵〈諫太 宗十思疏〉） 根據上文，可以知道魏徵以下列那一項是一個領導決策者必須具備的核心能力？', '["聰明睿智，善於謀事", "言出必行，忠君愛民", "武勇過人，威震天下", "知人善任，從善如流"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07092', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '人之良，孰願為盜也，由長民者失於教養，凍餒之極，遂至於此，要非其得已也。嘗潛體其然，使父饑 母寒，妻子慍見，徵負旁午，疹疫交攻，萬死一生，朝不逮暮，於斯時也，見利而不回者，能幾何人？ 其或因而攘竊，不原其情，輒置諸理，嬰笞關木，彼固無辭。然百需叢身，孰明其不獲已哉？古人謂： 「上失其道，民散久矣。如得其情，則哀矜而勿喜。」嗚呼！人能以是論囚，雖欲慘酷，亦必有所不忍矣。 下列那一選項與本文意旨最接近？', '["矜孤養老，邦家之大政", "安時興化，貴在慎獄存恕", "明君治難於其易，去惡於其微", "仁君在上，則海內無餒殍之人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07093', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「徐渭，字文長，為山陰諸生，聲名籍甚。薛公蕙校越時，奇其才，有國士之目。然數奇，屢試輒蹶。 中丞胡公宗憲聞之，客諸幕。」（袁宏道〈徐文長傳〉） 「然數奇，屢試輒蹶」一句中，「奇」的意涵與下列那一選項相同？', '["命運不好", "超乎尋常", "令人驚異", "怪異難解"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07094', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '古者諫無官，自公卿大夫，至於工商，無不得諫者。漢興以來，始置官。夫以天下之政，四海之眾， 得失利病，萃於一官。使言之，其為任亦重矣。居是官者，當志其大，舍其細，先其急，後其緩，專利 國家，而不為身謀。（司馬光〈諫院題名記〉） 下列敘述何者最貼近上文所強調的諫官之德？', '["知所不為，行己有恥", "權衡輕重，先公後私", "察納雅言，隱惡揚善", "見利思義，見危授命"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07095', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '衛人嫁其子而教之曰：「必私積聚。為人婦而出，常也；其成居，幸也。」其子因私積聚，其姑以為多 私而出之。其子所以反者，倍其所以嫁。其父不自罪於教子非也，而自知其益富。今人臣之處官者，皆 是類也。（《韓非子．說林上》） 以下選項何者最接近「今人臣之處官者」的啟示？', '["為官者愛財，也應取之有道", "為官者若無遠慮，必有近憂", "為官者勿營私好利，以免招禍", "為官首重廉，不廉則無所不取"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07096', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '齊侯問于晏子曰：「為政何患？」對曰：「患善惡之不分。」公曰：「何以察之？」對曰：「審擇左右， 左右善，則百僚各得其所宜而善惡分。」孔子聞之曰：「此言也信矣，善言進，則不善無由入矣；不進 善言，則善無由入矣。」（《說苑．政理》） 下列敘述何者最貼近上文？', '["為政必須明辨是非善惡", "為政必須考慮左右先後的步驟", "百官各司其職則政通人和", "百官多進善言，則各得所宜"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07097', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '余光中《青銅一夢．山東甘旅》：「清明節前一星期，我的飛機降落在濟南的遙墻機場。邀請我去齊魯訪 問的雖然是山東大學，真正遠去郊外歡迎的，沒有料到，卻是整個春天。從機場進城，三十公里的高速', '["但兩側的柳樹綠蔭不斷，料峭的晴冷天氣", "千樹新綠排成整齊的春之儀隊", "牽著連綿的青帳翠屏", "那樣盛況的陣仗 下列選項的順序安排，最適合的是："]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07098', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列文句「」中的成語，何者敘述不當？', '["曾經紅極一時的流行歌曲，在新人新曲競出之後，還是不免成了「明日黃花」", "暢銷書作家常到處演講，成天奔波趕場的狀況幾乎可用「席不暇暖」來形容", "為了達到目的而製造各種謠言來攻擊他人，就有如「蜀犬吠日」，終於有被揭發的一天", "為了不受外界干擾，他「息交絕遊」了一年，斷絕所有的應酬跟娛樂，終於通過了公務人員考試"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07099', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '藉由形象化的語言來描繪抽象的情思，可使讀者獲得更鮮明的印象及感受。下列四個選項都運用這種技 巧，何者敘述最為正確？', '["孤獨是一匹衰老的獸／潛伏在我亂石磊磊的心裡──以衰老的獸描寫孤獨離我遠去（楊牧〈孤獨〉）", "問君能有幾多愁？恰似一江春水向東流──以江水東流的方向指出憂愁來源在東方（李煜〈虞美人〉）", "一隻苦瓜，不再是澀苦／日磨月磋琢出深孕的清瑩──苦瓜的外表清瑩，所以不苦（余光中〈白玉苦 瓜〉）", "忽然想起／感傷是微微的了／如遠去的船／船邊的水紋……──傷感似水紋般越來越淡、越小（敻虹〈 水紋〉）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
